import{_ as a,o as r,c as t,a3 as o}from"./chunks/framework.CjquFG0V.js";const u=JSON.parse('{"title":"63. Jury Service Leave","description":"","frontmatter":{"title":"63. Jury Service Leave","eba":"Health Allied & Managers Admin 2021-2025","topics":["leave"]},"headers":[],"relativePath":"ebas/has-managers-admin/common-terms/leave/63-jury-service-leave.md","filePath":"ebas/has-managers-admin/common-terms/leave/63-jury-service-leave.md"}'),n={name:"ebas/has-managers-admin/common-terms/leave/63-jury-service-leave.md"};function s(i,e,l,c,m,d){return r(),t("div",null,[...e[0]||(e[0]=[o('<h1 id="_63-jury-service-leave" tabindex="-1">63. Jury Service Leave <a class="header-anchor" href="#_63-jury-service-leave" aria-label="Permalink to &quot;63. Jury Service Leave&quot;">​</a></h1><p><strong>63.1</strong> An Employee required to attend for jury service will be reimbursed by the Employer an amount equal to the difference between:</p><p><strong>(a)</strong> the amount paid by the state of Victoria in respect of attendance for jury service; and</p><p><strong>(b)</strong> the amount the Employee could reasonably expect to have received from the Employer as earnings for that period had the Employee not been performing jury service.</p><p><strong>63.2</strong> An Employee will notify the Employer as soon as possible of the date they are required to attend jury service. The Employee will give the Employer proof of attendance at the court, the duration of such attendance and the amount received for jury service.</p><p>Plain language terms: jury duty, court leave.</p>',6)])])}const v=a(n,[["render",s]]);export{u as __pageData,v as default};
